import React, { useState } from 'react';
import { useData } from '../../context/DataContext';

const StaffManager = () => {
  // Lấy thêm shifts và các hàm xử lý từ Context
  const { staffList, addStaff, deleteStaff, updatePassword, shifts, addShift, deleteShift } = useData(); 
  
  // State form nhân sự (Thêm shiftId)
  const [formData, setFormData] = useState({ name: '', username: '', password: '', shiftId: '' });
  
  // State form tạo ca làm việc mới
  const [shiftForm, setShiftForm] = useState({ name: '', start: '', end: '' });

  // --- XỬ LÝ NHÂN SỰ ---
  const handleAddStaff = (e) => {
    e.preventDefault();
    if (staffList.some(s => s.username === formData.username)) {
      alert("Tên đăng nhập đã tồn tại!");
      return;
    }
    // Bắt buộc chọn ca
    if (!formData.shiftId) {
      alert("Vui lòng chọn Ca làm việc cho nhân sự!");
      return;
    }
    addStaff({ ...formData, role: 'staff' });
    setFormData({ name: '', username: '', password: '', shiftId: '' });
    alert("Đã tạo tài khoản thành công");
  };

  const handleDeleteStaff = (id) => {
    if (window.confirm("Bạn có chắc chắn muốn xóa nhân sự này?")) {
      deleteStaff(id);
    }
  };

  const handleResetPassword = (id, name) => {
    const newPass = prompt(`Nhập mật khẩu mới cho nhân sự ${name}:`);
    if (newPass) {
      updatePassword(id, newPass);
      alert(`Đã đổi mật khẩu cho ${name} thành công.`);
    }
  };

  // --- XỬ LÝ CA LÀM VIỆC ---
  const handleAddShift = (e) => {
    e.preventDefault();
    if (!shiftForm.name || !shiftForm.start || !shiftForm.end) return;
    
    // Kiểm tra logic giờ (Start < End) nếu cần, ở đây làm đơn giản
    addShift(shiftForm);
    setShiftForm({ name: '', start: '', end: '' });
    alert("Đã thêm ca làm việc mới");
  };

  const handleDeleteShift = (id) => {
    if (window.confirm("Xóa ca làm việc này có thể ảnh hưởng đến các nhân sự đang được gán. Bạn có chắc chắn?")) {
      deleteShift(id);
    }
  };

  return (
    <div>
      {/* --- PHẦN 1: QUẢN LÝ CA LÀM VIỆC --- */}
      <div style={{ marginBottom: '30px', borderBottom: '2px solid #ddd', paddingBottom: '20px' }}>
        <h2 style={{ color: '#003366' }}>1. Quản lý Ca làm việc</h2>
        <div style={{ display: 'flex', gap: '20px', alignItems: 'flex-start', flexWrap: 'wrap' }}>
          
          {/* Form thêm ca */}
          <form onSubmit={handleAddShift} style={{ background: '#e6f7ff', padding: '15px', borderRadius: '8px', border: '1px solid #91d5ff', minWidth: '250px' }}>
            <h4 style={{ margin: '0 0 10px 0', color: '#0050b3' }}>+ Thêm Ca mới</h4>
            <div style={{ marginBottom: '10px' }}>
              <input 
                placeholder="Tên ca (VD: Ca Sáng)" 
                value={shiftForm.name} 
                onChange={e => setShiftForm({...shiftForm, name: e.target.value})} 
                required 
                style={{ width: '100%', padding: '5px', boxSizing: 'border-box' }} 
              />
            </div>
            <div style={{ display: 'flex', gap: '10px', marginBottom: '10px' }}>
              <div style={{ flex: 1 }}>
                <span style={{ fontSize: '0.8rem', fontWeight: 'bold' }}>Bắt đầu:</span>
                <input 
                  type="time" 
                  value={shiftForm.start} 
                  onChange={e => setShiftForm({...shiftForm, start: e.target.value})} 
                  required 
                  style={{ width: '100%', padding: '5px', boxSizing: 'border-box' }} 
                />
              </div>
              <div style={{ flex: 1 }}>
                <span style={{ fontSize: '0.8rem', fontWeight: 'bold' }}>Kết thúc:</span>
                <input 
                  type="time" 
                  value={shiftForm.end} 
                  onChange={e => setShiftForm({...shiftForm, end: e.target.value})} 
                  required 
                  style={{ width: '100%', padding: '5px', boxSizing: 'border-box' }} 
                />
              </div>
            </div>
            <button type="submit" style={{ background: '#1890ff', color: 'white', border: 'none', padding: '8px 15px', borderRadius: '4px', cursor: 'pointer', width: '100%', fontWeight: 'bold' }}>
              Lưu Ca
            </button>
          </form>

          {/* Danh sách ca */}
          <div style={{ flex: 1, minWidth: '300px' }}>
            <table border="1" style={{ width: '100%', borderCollapse: 'collapse', background: 'white' }}>
              <thead style={{ background: '#fafafa' }}>
                <tr>
                  <th style={{ padding: '8px' }}>Tên Ca</th>
                  <th style={{ padding: '8px' }}>Bắt đầu</th>
                  <th style={{ padding: '8px' }}>Kết thúc</th>
                  <th style={{ padding: '8px' }}>Thao tác</th>
                </tr>
              </thead>
              <tbody>
                {shifts.length === 0 ? <tr><td colSpan="4" style={{textAlign:'center', padding:'10px'}}>Chưa có ca làm việc</td></tr> : null}
                {shifts.map(s => (
                  <tr key={s.id}>
                    <td style={{ padding: '8px', fontWeight: 'bold' }}>{s.name}</td>
                    <td style={{ padding: '8px' }}>{s.start}</td>
                    <td style={{ padding: '8px' }}>{s.end}</td>
                    <td style={{ padding: '8px', textAlign: 'center' }}>
                      <button 
                        onClick={() => handleDeleteShift(s.id)} 
                        style={{ color: 'red', cursor: 'pointer', border: 'none', background: 'none', fontWeight: 'bold' }}
                      >
                        Xóa
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* --- PHẦN 2: QUẢN LÝ NHÂN SỰ --- */}
      <div>
        <h2 style={{ color: '#003366' }}>2. Quản lý Tài khoản Nhân sự</h2>
        <div style={{ display: 'flex', gap: '20px', alignItems: 'flex-start' }}>
          
          {/* Form tạo nhân sự */}
          <form onSubmit={handleAddStaff} style={{ padding: '15px', background: '#f9f9f9', borderRadius: '8px', border: '1px solid #ddd', minWidth: '250px' }}>
            <h4 style={{ margin: '0 0 10px 0' }}>Thêm nhân sự mới</h4>
            <input placeholder="Họ tên" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required style={{display: 'block', marginBottom: '10px', width: '100%', padding: '8px', boxSizing: 'border-box'}}/>
            <input placeholder="Tên đăng nhập" value={formData.username} onChange={e => setFormData({...formData, username: e.target.value})} required style={{display: 'block', marginBottom: '10px', width: '100%', padding: '8px', boxSizing: 'border-box'}}/>
            <input placeholder="Mật khẩu" type="password" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} required style={{display: 'block', marginBottom: '10px', width: '100%', padding: '8px', boxSizing: 'border-box'}}/>
            
            {/* Dropdown chọn Ca làm việc */}
            <select 
              value={formData.shiftId} 
              onChange={e => setFormData({...formData, shiftId: e.target.value})} 
              required 
              style={{display: 'block', marginBottom: '15px', width: '100%', padding: '8px', boxSizing: 'border-box', border: '1px solid #ccc', borderRadius: '4px'}}
            >
              <option value="">-- Chọn Ca làm việc --</option>
              {shifts.map(s => (
                <option key={s.id} value={s.id}>
                  {s.name} ({s.start} - {s.end})
                </option>
              ))}
            </select>

            <button type="submit" style={{ background: '#28a745', color: 'white', border: 'none', padding: '10px 15px', borderRadius: '4px', cursor: 'pointer', width: '100%', fontWeight: 'bold' }}>
              Tạo tài khoản
            </button>
          </form>

          {/* Danh sách nhân sự */}
          <div style={{ flex: 1 }}>
            <table border="1" style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left', background: 'white' }}>
              <thead style={{ background: '#eee' }}>
                <tr>
                  <th style={{ padding: '10px' }}>Họ tên</th>
                  <th style={{ padding: '10px' }}>Username</th>
                  <th style={{ padding: '10px' }}>Ca làm việc</th>
                  <th style={{ padding: '10px' }}>Thao tác</th>
                </tr>
              </thead>
              <tbody>
                {staffList.map(staff => {
                  // Tìm thông tin ca dựa trên shiftId
                  const shift = shifts.find(s => String(s.id) === String(staff.shiftId));
                  return (
                    <tr key={staff.id}>
                      <td style={{ padding: '10px' }}>{staff.name}</td>
                      <td style={{ padding: '10px' }}>{staff.username}</td>
                      <td style={{ padding: '10px' }}>
                        {shift ? (
                          <span style={{ color: '#0050b3', fontWeight: '500' }}>{shift.name} ({shift.start}-{shift.end})</span>
                        ) : (
                          <span style={{ color: 'red', fontStyle: 'italic' }}>Chưa xếp ca</span>
                        )}
                      </td>
                      <td style={{ padding: '10px' }}>
                        <button 
                          onClick={() => handleResetPassword(staff.id, staff.name)}
                          style={{ background: '#ffc107', color: '#000', border: 'none', padding: '5px 10px', borderRadius: '4px', cursor: 'pointer', marginRight: '5px' }}
                        >
                          Đổi MK
                        </button>
                        <button 
                          onClick={() => handleDeleteStaff(staff.id)}
                          style={{ background: '#dc3545', color: 'white', border: 'none', padding: '5px 10px', borderRadius: '4px', cursor: 'pointer' }}
                        >
                          Xóa
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default StaffManager;
